{
  "account_id": "{{account_id}}",
  "user_id": "{{user_id}}",
  "tenant_id": "{{tenant_id}}",
  "agent": {
    "name": "aws",
    "tool_config": "dev-new"
  },
  "test_indices": "0",

  // deploy_infra: false → skip infra deploy (command queries don't need it)
  "deploy_infra": false,
  "skip_nuke": false
}

{
  "account_id": "{{account_id}}",
  "user_id": "{{user_id}}",
  "tenant_id": "{{tenant_id}}",
  "agent": {
    "name": "aws",
    "tool_config": "dev-new"
  },

  // index 304 = E01 RCA scenario (SSH timeout on EC2 bastion)
  // index 305 = E02, 306 = E03 ... 333 = H10
  "test_indices": "304",

  // deploy_infra: true → deploy bootstrap VPC + E01 CloudFormation stack in Broken mode
  // Only the scenario(s) needed for the selected indices are deployed (not all 30)
  "deploy_infra": true,

  // skip_nuke: false → destroy all stacks after test completes
  // Set to true to keep infra up for debugging or re-runs
  "skip_nuke": false
}

{
  "account_id": "{{account_id}}",
  "user_id": "{{user_id}}",
  "tenant_id": "{{tenant_id}}",
  "agent": {
    "name": "aws",
    "tool_config": "dev-new"
  },
  "test_indices": "304",

  // deploy_infra: true  → deploy bootstrap + E01 stack
  "deploy_infra": true,

  // skip_nuke: true → leave infrastructure up after test
  // Use this when you want to re-run the test without redeploying
  // Remember to manually nuke when done: bash scripts/nuke.sh
  "skip_nuke": true
}

{
  "account_id": "{{account_id}}",
  "user_id": "{{user_id}}",
  "tenant_id": "{{tenant_id}}",
  "agent": {
    "name": "aws",
    "tool_config": "dev-new"
  },
  "test_indices": "304",

  // deploy_infra: false → skip deploy, infra is already up from a previous run
  "deploy_infra": false,

  // skip_nuke: false → nuke after this run (set true to keep up again)
  "skip_nuke": false
}

{
  "account_id": "{{account_id}}",
  "user_id": "{{user_id}}",
  "tenant_id": "{{tenant_id}}",
  "agent": {
    "name": "aws",
    "tool_config": "dev-new"
  },

  // No test_indices → run ALL 334 queries (304 command + 30 RCA)

  // deploy_infra: true → deploy bootstrap + all 30 scenarios (E01-E10, M01-M10, H01-H10)
  // WARNING: This takes ~30-40 min to deploy before tests start
  "deploy_infra": true,

  // skip_nuke: false → destroy everything after all tests complete
  "skip_nuke": false,

  "cc_emails": ["team@example.com"]
}

{
  "account_id": "{{account_id}}",
  "user_id": "{{user_id}}",
  "tenant_id": "{{tenant_id}}",
  "agent": {
    "name": "azure",
    "tool_config": "dev-new"
  },

  // index 20 = E01 RCA (SSH into bastion NSG)
  // index 21 = E02, 22 = E03 ... 29 = E10
  // index 30 = M01, 31 = M02 ... 39 = M10
  "test_indices": "20",

  // deploy_infra: true → deploy bootstrap (shared App Service Plan) + E01 resource group
  "deploy_infra": true,

  // skip_nuke: false → delete resource groups after test
  // Note: Azure deletes RGs asynchronously in the background
  "skip_nuke": false
}

{
  "account_id": "{{account_id}}",
  "user_id": "{{user_id}}",
  "tenant_id": "{{tenant_id}}",
  "agent": "azure",

  // indices 0-19 are command queries, no infra needed
  "test_indices": "0",

  "deploy_infra": false,
  "skip_nuke": false
}
